{
  "clauseRiskSummary": "This clause outlines indemnification responsibilities for both parties in case of third-party claims, potentially exposing the non-operator to significant financial risk.",
  "operative_text": "10) Indemnification   COMPANY shall indemnify Bravatek, its directors, officers and employees, for any and all damages, costs, expenses, and other liabilities, including reasonable attorney's fees and court costs incurred in connection with any third-party claim, action or proceeding arising from the negligence or intentional misconduct of COMPANY or breach of COMPANY of any of its obligations under this Agreement.   Bravatek shall indemnify COMPANY, its directors, officers and employees, for any and all damages, costs, expenses, and other liabilities, including reasonable attorney's fees and court costs, incurred in connection with any third-party claim, action or proceeding arising from the negligence or intentional misconduct of Bravatek or breach of Bravatek of any of its obligations under this Agreement.",
  "concerns": [
    {
      "text": "This clause outlines indemnification responsibilities for both parties in case of third-party claims. This could expose the non-operator to significant financial risk if a claim arises from the negligence or intentional misconduct of the operator, as per the 'COMPANY' and 'Bravatek' clauses.",
      "severity": "major",
      "references": ["COMPANY", "Bravatek"]
    }
  ],
  "favoursWhom": "operator" 
}

